import{_ as n,o as i,c as e,ag as a}from"./chunks/framework.BZohXCq9.js";const p=JSON.parse('{"title":"[Client/App] Kho tính năng: Hiển thị Nội dung (Display & UI)","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/client-app-display.md","filePath":"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/client-app-display.md"}'),h={name:"99-tham-khao/archive/03-kho-tinh-nang/quan-tri-noi-dung/client-app-display.md"};function l(r,t,o,g,s,d){return i(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="client-app-kho-tinh-nang-hien-thi-noi-dung-display-ui" tabindex="-1">[Client/App] Kho tính năng: Hiển thị Nội dung (Display &amp; UI) <a class="header-anchor" href="#client-app-kho-tinh-nang-hien-thi-noi-dung-display-ui" aria-label="Permalink to &quot;[Client/App] Kho tính năng: Hiển thị Nội dung (Display &amp; UI)&quot;">​</a></h1><table tabindex="0"><thead><tr><th style="text-align:left;">Phiên bản</th><th style="text-align:left;">Ngày</th><th style="text-align:left;">Sprint</th><th style="text-align:left;">Nội dung thay đổi</th><th style="text-align:left;">Người thực hiện</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>v1.0</strong></td><td style="text-align:left;">26/03/2026</td><td style="text-align:left;"><a href="./../../02-quan-ly-sprint/sprint-2-quan-tri-diem-den/01-yeu-cau-nghiep-vu">Sprint 2</a></td><td style="text-align:left;">Khởi tạo mô tả hiển thị Client/App ban đầu</td><td style="text-align:left;">PO</td></tr></tbody></table><hr><p>Thông tin nội dung (Tour, Điểm đến) được hiển thị linh hoạt trên Web Client và Mobile App.</p><h2 id="_1-gallery-media-center" tabindex="-1">1. Gallery &amp; Media Center <a class="header-anchor" href="#_1-gallery-media-center" aria-label="Permalink to &quot;1. Gallery &amp; Media Center&quot;">​</a></h2><ul><li><strong>Chi tiết</strong>: Hiển thị ảnh Slider/Carousel tại màn hình Detail.</li><li><strong>Tính năng</strong>: Hỗ trợ Zoom ảnh, xem ảnh theo grid.</li><li><strong>Phản hồi</strong>: Tự động tối ưu định dạng ảnh WebP cho thiết bị di động.</li></ul><h2 id="_2-thong-tin-điem-đen-destination-directory" tabindex="-1">2. Thông tin Điểm đến (Destination Directory) <a class="header-anchor" href="#_2-thong-tin-điem-đen-destination-directory" aria-label="Permalink to &quot;2. Thông tin Điểm đến (Destination Directory)&quot;">​</a></h2><ul><li><strong>Chi tiết</strong>: Hiển thị danh sách ảnh &amp; tên vùng miền dưới dạng Card.</li><li><strong>Tính năng</strong>: <ul><li>Click vào card đi tới danh sách Tour cùng vùng miền.</li><li>Hiển thị mô tả ngắn (Excerpt) tối đa 150 ký tự.</li></ul></li></ul><h2 id="_3-lich-trinh-tour-itinerary-display" tabindex="-1">3. Lịch trình Tour (Itinerary Display) <a class="header-anchor" href="#_3-lich-trinh-tour-itinerary-display" aria-label="Permalink to &quot;3. Lịch trình Tour (Itinerary Display)&quot;">​</a></h2><ul><li><strong>Chi tiết</strong>: Hiển thị hành trình theo Ngày 1, Ngày 2...</li><li><strong>Tính năng</strong>: <ul><li>Hiển thị theo dạng Timeline (Dòng thời gian).</li><li>Hỗ trợ ảnh minh họa cho từng hoạt động con trong tour.</li></ul></li></ul><h2 id="_4-tuong-tac-nguoi-dung-engagement" tabindex="-1">4. Tương tác Người dùng (Engagement) <a class="header-anchor" href="#_4-tuong-tac-nguoi-dung-engagement" aria-label="Permalink to &quot;4. Tương tác Người dùng (Engagement)&quot;">​</a></h2><ul><li><strong>Tính năng</strong>: Nút &quot;Yêu thích&quot; (Save to wishlist).</li><li><strong>Phản hồi</strong>: Lưu vào Session/Database để xem lại sau.</li></ul><hr><p><em>Kho tính năng người dùng cuối.</em></p>',14)])])}const c=n(h,[["render",l]]);export{p as __pageData,c as default};
